mapper.select:
/* wms-master-icmanager-sql-oracle.xml - selectIbMstIcMap - 상품 정보 */
SELECT *
FROM TWORK_MST_IC
WHERE CTKEY = #{ctkey}
AND OWKEY = COALESCE(#{OWKEY}, #{sowkey})
AND ICKEY = #{ickey}

/* wms-master-icmanager-sql-oracle.xml - selectIbMstIcutxtypeMap - 상품 단위 유형 마스터 조회 */
SELECT *
  FROM TWORK_MST_ICUTXTYPE
 WHERE CTKEY = #{ctkey}
   AND OWKEY = COALESCE(#{OWKEY}, #{sowkey})
   AND ICUNITKEY = #{icunitkey}
   AND ICUNITTYPECD = 'EA'

/* wms-master-icmanager-sql-oracle.xml - selectIcUom - 단위 정보 조회 */
SELECT B.ICUNITTYPECD
	 , B.ICUNITQTY
  FROM TWORK_MST_IC A
 INNER JOIN TWORK_MST_ICUTXTYPE B
	ON A.CTKEY = B.CTKEY
   AND A.OWKEY = B.OWKEY
   AND A.ICUNITKEY = B.ICUNITKEY
 WHERE A.CTKEY = #{ctkey}
   AND A.OWKEY = #{owkey}
   AND A.ICKEY = #{ickey}
